#!/usr/bin/env python3
# scripts/compute_launch_thresholds.py
# Queries Prometheus for baseline metrics and computes recommended thresholds.
import requests, os, json, statistics
from datetime import datetime, timedelta, timezone

PROM = os.environ["PROMETHEUS_URL"]

def query_range(metric_expr, start, end, step="5m"):
    resp = requests.get(f"{PROM}/api/v1/query_range", params={
        "query": metric_expr, "start": start, "end": end, "step": step
    })
    resp.raise_for_status()
    return resp.json()["data"]["result"]

def percentile(values, p):
    s = sorted(values)
    idx = int(len(s) * p / 100)
    return s[min(idx, len(s) - 1)]

now = datetime.now(timezone.utc)
baseline_start = (now - timedelta(days=14)).timestamp()
baseline_end = (now - timedelta(hours=1)).timestamp()

service = os.environ.get("SERVICE", "triage-api")

# Error rate baseline
error_results = query_range(
    f'sum(rate(http_requests_total{{service="{service}",status=~"5.."}}[5m])) / '
    f'sum(rate(http_requests_total{{service="{service}"}}[5m]))',
    baseline_start, baseline_end
)
error_values = [float(v[1]) for r in error_results for _, v in [(r["values"][i], r["values"][i]) for i in range(len(r["values"]))]]

# Simplify: flatten all values
all_errors = []
for r in error_results:
    for ts, v in r["values"]:
        if v != "NaN":
            all_errors.append(float(v))

# Latency p99 baseline
latency_results = query_range(
    f'histogram_quantile(0.99, rate(http_request_duration_seconds_bucket{{service="{service}"}}[5m]))',
    baseline_start, baseline_end
)
all_latency = []
for r in latency_results:
    for ts, v in r["values"]:
        if v != "NaN":
            all_latency.append(float(v))

if all_errors:
    baseline_error = percentile(all_errors, 95)  # 95th pct of baseline error rate
    thresholds = {
        "error_rate": {
            "baseline_p95": round(baseline_error, 5),
            "p0_threshold": round(baseline_error * 3.0, 5),
            "p1_threshold": round(baseline_error * 1.5, 5),
            "p2_threshold": round(baseline_error * 1.1, 5),
        }
    }
    if all_latency:
        baseline_p99 = percentile(all_latency, 95)
        thresholds["latency_p99_seconds"] = {
            "baseline_p95": round(baseline_p99, 4),
            "p0_threshold": round(baseline_p99 * 2.0, 4),
            "p1_threshold": round(baseline_p99 * 1.25, 4),
            "p2_threshold": round(baseline_p99 * 1.1, 4),
        }
    print(json.dumps(thresholds, indent=2))
    print(f"\n# Baselines computed from {len(all_errors)} error samples, "
          f"{len(all_latency)} latency samples over 14-day window")
else:
    print("ERROR: no data returned — check PROMETHEUS_URL and service label")
    exit(1)

#!/usr/bin/env python3
# scripts/check_launch_criteria.py
# Exit 0 = all criteria met (or only P2 warnings)
# Exit 1 = P1 violations (conditional; DRI accept present → proceed)
# Exit 2 = P0 violations (hard block regardless of DRI accept)
import yaml, sys, json, subprocess, os
from pathlib import Path

launch_path = Path(sys.argv[1])
launch = yaml.safe_load(launch_path.read_text())
criteria = launch.get("launch_criteria", {})

# --- Helpers ---
def measure_prometheus(query, window_minutes, prom_url):
    import requests
    from datetime import datetime, timezone
    end = datetime.now(timezone.utc).timestamp()
    start = end - window_minutes * 60
    resp = requests.get(f"{prom_url}/api/v1/query", params={
        "query": f"avg_over_time(({query})[{window_minutes}m:1m])"
    })
    result = resp.json()["data"]["result"]
    if not result:
        return None
    return float(result[0]["value"][1])

def measure_tool(tool_cmd):
    result = subprocess.run(tool_cmd.split(), capture_output=True, text=True)
    if result.returncode != 0:
        return None
    # Expect tool to print a JSON object with "score" key
    try:
        return json.loads(result.stdout)["score"]
    except Exception:
        return float(result.stdout.strip())

PROM = os.environ.get("PROMETHEUS_URL", "http://prometheus:9090")
p0_violations = []
p1_violations = []
p2_warnings = []

for criterion_name, spec in criteria.items():
    if criterion_name == "canary":
        continue  # canary health checked separately by deploy script

    meas = spec.get("measurement", {})
    current = None

    if "query" in meas:
        current = measure_prometheus(meas["query"], meas.get("window_minutes", 10), PROM)
    elif "tool" in meas:
        current = measure_tool(meas["tool"])

    if current is None:
        print(f"  [SKIP] {criterion_name}: could not measure")
        continue

    spec["current_value"] = current
    thresholds = spec.get("thresholds", {})
    higher = spec.get("higher_is_better", False)

    def violates(current, threshold, higher_is_better):
        if threshold is None:
            return False
        return current < threshold if higher_is_better else current > threshold

    if violates(current, thresholds.get("p0"), higher):
        p0_violations.append(f"  [P0] {criterion_name}: {current:.5f} violates {thresholds['p0']}")
    elif violates(current, thresholds.get("p1"), higher):
        p1_violations.append(f"  [P1] {criterion_name}: {current:.5f} (threshold: {thresholds['p1']})")
    elif violates(current, thresholds.get("p2"), higher):
        p2_warnings.append(f"  [P2] {criterion_name}: {current:.5f} (threshold: {thresholds['p2']})")
    else:
        print(f"  [OK] {criterion_name}: {current:.5f}")

# Persist updated current_values back to the launch YAML
launch["launch_criteria"] = criteria
launch_path.write_text(yaml.dump(launch, default_flow_style=False, sort_keys=False))

# Report
if p2_warnings:
    print("\nP2 WARNINGS (proceed with monitoring):")
    for w in p2_warnings:
        print(w)

if p1_violations:
    print("\nP1 VIOLATIONS (conditional — DRI risk acceptance required):")
    for v in p1_violations:
        print(v)

if p0_violations:
    print("\nP0 VIOLATIONS (hard block — Go/No-Go must be NO-GO):")
    for v in p0_violations:
        print(v)
    sys.exit(2)

# Check for DRI acceptance of P1 violations
if p1_violations:
    gng = launch.get("go_no_go", {})
    dri_accepted = gng.get("dri_override", False) and gng.get("dri_override_rationale")
    if not dri_accepted:
        print("\nP1 violations present but no DRI risk acceptance recorded.")
        print("Record acceptance in go_no_go.dri_override_rationale before proceeding.")
        sys.exit(1)
    else:
        print(f"\nP1 violations accepted by DRI: {gng['dri_override_rationale']}")

print("\nAll launch criteria passed (or P1 violations DRI-accepted).")
sys.exit(0)

#!/usr/bin/env python3
# scripts/detect_threshold_drift.py
# Compares current baseline metrics against the thresholds in a launch YAML.
# Reports thresholds that are significantly misaligned with current reality.
import yaml, requests, os, json
from pathlib import Path
from datetime import datetime, timedelta, timezone

PROM = os.environ["PROMETHEUS_URL"]
DRIFT_FACTOR = 2.0  # flag if current baseline differs from stored baseline by > 2×

def current_baseline(query, window_days=7):
    end = datetime.now(timezone.utc).timestamp()
    start = (datetime.now(timezone.utc) - timedelta(days=window_days)).timestamp()
    resp = requests.get(f"{PROM}/api/v1/query_range", params={
        "query": query, "start": start, "end": end, "step": "5m"
    })
    results = resp.json()["data"]["result"]
    values = [float(v[1]) for r in results for _, v in [("", x) for x in r["values"]] if v[1] != "NaN"]
    if not values:
        return None
    import statistics
    return statistics.median(values)

# Load all launch YAML files
launch_dir = Path("docs/launches")
drift_report = []

for launch_path in sorted(launch_dir.glob("*.yaml")):
    launch = yaml.safe_load(launch_path.read_text())
    criteria = launch.get("launch_criteria", {})

    for crit_name, spec in criteria.items():
        meas = spec.get("measurement", {})
        if "query" not in meas:
            continue
        stored_baseline = spec.get("baseline")
        if stored_baseline is None:
            continue

        live_baseline = current_baseline(meas["query"])
        if live_baseline is None:
            continue

        ratio = live_baseline / stored_baseline if stored_baseline > 0 else float("inf")
        if ratio > DRIFT_FACTOR or ratio < (1 / DRIFT_FACTOR):
            drift_report.append({
                "launch": launch_path.name,
                "criterion": crit_name,
                "stored_baseline": stored_baseline,
                "live_baseline": live_baseline,
                "ratio": ratio,
                "action": "re-baseline recommended"
            })

if drift_report:
    print(f"THRESHOLD DRIFT DETECTED ({len(drift_report)} criteria):")
    for item in drift_report:
        print(f"  {item['launch']} / {item['criterion']}: "
              f"stored={item['stored_baseline']:.5f}, "
              f"live={item['live_baseline']:.5f}, "
              f"ratio={item['ratio']:.1f}× — {item['action']}")
else:
    print("No threshold drift detected.")
